      ratioRows: [],
      stateCode: 'TX',
      expectedProfileShape: {
        stateCode: 'TX',
        stateName: 'Texas',
        totalObligated: 80000,
        totalAwardCount: 4,
        ratios: [],
        declarationCount: 0,
      },
    },
    {
      name: 'returns null when state code has no data',
      fundingRows: [],
      ratioRows: [],
      stateCode: 'ZZ',
      expectedProfileShape: null,
    },
